-- Simple XML parser that handles entity references
-- This avoids external dependencies while being suitable for OpenResty

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference map
local default_entities = {
    ["&amp;"]  = "&",
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

function XmlParser.new()
    local self = setmetatable({}, XmlParser)
    self.entities = {}
    for k, v in pairs(default_entities) do
        self.entities[k] = v
    end
    return self
end

function XmlParser:resolve_entities(text)
    if not text then
        return text
    end
    -- Resolve named entities
    for entity, replacement in pairs(self.entities) do
        text = text:gsub(entity, replacement)
    end
    -- Resolve numeric character references (decimal)
    text = text:gsub("&#(%d+);", function(n)
        return string.char(tonumber(n))
    end)
    -- Resolve numeric character references (hex)
    text = text:gsub("&#x(%x+);", function(n)
        return string.char(tonumber(n, 16))
    end)
    return text
end

function XmlParser:parse_attributes(attr_str)
    local attrs = {}
    if not attr_str or attr_str == "" then
        return attrs
    end
    for name, value in attr_str:gmatch('([%w_:%-]+)%s*=%s*"([^"]*)"') do
        attrs[name] = self:resolve_entities(value)
    end
    for name, value in attr_str:gmatch("([%w_:%-]+)%s*=%s*'([^']*)'") do
        attrs[name] = self:resolve_entities(value)
    end
    return attrs
end

function XmlParser:parse(xml_str)
    if not xml_str or xml_str == "" then
        return nil, "Empty XML input"
    end

    -- Remove XML declaration
    xml_str = xml_str:gsub("<%?xml[^%?]*%?>", "")

    -- Extract custom entity definitions from DOCTYPE if present
    local doctype = xml_str:match("<!DOCTYPE[^>]*%[(.-)%]>")
    if doctype then
        for entity_name, entity_value in doctype:gmatch('<!ENTITY%s+(%w+)%s+"([^"]*)"%s*>') do
            self.entities["&" .. entity_name .. ";"] = entity_value
        end
    end
    -- Remove DOCTYPE
    xml_str = xml_str:gsub("<!DOCTYPE[^>]*>", "")
    xml_str = xml_str:gsub("<!DOCTYPE[^%[]*%[.-%]>", "")

    -- Remove comments
    xml_str = xml_str:gsub("<!%-%-.-%--%>", "")

    -- Remove CDATA sections by extracting content
    xml_str = xml_str:gsub("<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { _type = "root", _children = {}, _name = "root" }
    local current = root

    table.insert(stack, current)

    local pos = 1
    while pos <= #xml_str do
        local text_start, tag_start = xml_str:find("<", pos)

        if not text_start then
            -- Remaining text
            local remaining = xml_str:sub(pos):match("^%s*(.-)%s*$")
            if remaining and remaining ~= "" then
                current._text = (current._text or "") .. self:resolve_entities(remaining)
            end
            break
        end

        -- Text before tag
        if text_start > pos then
            local text = xml_str:sub(pos, text_start - 1)
            local trimmed = text:match("^%s*(.-)%s*$")
            if trimmed and trimmed ~= "" then
                current._text = (current._text or "") .. self:resolve_entities(trimmed)
            end
        end

        -- Self-closing tag
        local self_close_tag, self_close_attrs = xml_str:match("^<([%w_:%-]+)(.-)/>", tag_start)
        if self_close_tag then
            local node = {
                _type = "element",
                _name = self_close_tag,
                _attrs = self:parse_attributes(self_close_attrs),
                _children = {},
                _text = nil,
            }
            table.insert(current._children, node)
            current[self_close_tag] = current[self_close_tag] or {}
            if type(current[self_close_tag]) ~= "table" or current[self_close_tag]._type then
                current[self_close_tag] = { current[self_close_tag] }
            end
            table.insert(current[self_close_tag], node)

            pos = xml_str:find("/>", tag_start) + 2
        else
            -- Closing tag
            local close_tag = xml_str:match("^</([%w_:%-]+)%s*>", tag_start)
            if close_tag then
                if current._name ~= close_tag then
                    return nil, "Mismatched closing tag: expected </" .. (current._name or "?") .. "> but found </" .. close_tag .. ">"
                end
                table.remove(stack)
                current = stack[#stack]
                pos = xml_str:find(">", tag_start) + 1
            else
                -- Opening tag
                local open_tag, open_attrs = xml_str:match("^<([%w_:%-]+)(.-[^/])>", tag_start)
                if not open_tag then
                    open_tag = xml_str:match("^<([%w_:%-]+)>", tag_start)
                    open_attrs = ""
                end

                if open_tag then
                    local node = {
                        _type = "element",
                        _name = open_tag,
                        _attrs = self:parse_attributes(open_attrs or ""),
                        _children = {},
                        _text = nil,
                    }
                    table.insert(current._children, node)

                    -- Store by tag name for easy access
                    if not current[open_tag] then
                        current[open_tag] = node
                    else
                        -- Multiple children with same name -> convert to array
                        if current[open_tag]._type then
                            current[open_tag] = { current[open_tag] }
                        end
                        table.insert(current[open_tag], node)
                    end

                    table.insert(stack, node)
                    current = node
                    pos = xml_str:find(">", tag_start) + 1
                else
                    -- Skip unrecognized
                    pos = tag_start + 1
                end
            end
        end
    end

    if #root._children == 0 then
        return nil, "No root element found"
    end

    return root._children[1]
