-- Helper: get text content of a node (recursive)
local function get_text(node)
    if not node then
        return nil
    end
    if type(node) == "string" then
        return node
    end
    if node._text then
        return node._text
    end
    -- Concatenate text from children
    local parts = {}
    if node._children then
        for _, child in ipairs(node._children) do
            local t = get_text(child)
            if t then
                table.insert(parts, t)
            end
        end
    end
    if #parts > 0 then
        return table.concat(parts, "")
    end
    return nil
end

-- Helper: find a node by path (e.g., "soap:Envelope/soap:Body/GetUser")
local function find_node(root, path)
    local current = root
    for segment in path:gmatch("[^/]+") do
        if not current then
            return nil
        end
        current = current[segment]
        -- If it's an array, take the first element
        if current and not current._type and type(current) == "table" then
            current = current[1]
        end
    end
    return current
end

-- Helper: get attribute value
local function get_attr(node, attr_name)
    if node and node._attrs then
        return node._attrs[attr_name]
    end
    return nil
end

-- Helper: get local name (strip namespace prefix)
local function local_name(name)
    if not name then return nil end
    return name:match(":(.+)") or name
end

-- Helper: find node ignoring namespace prefixes
local function find_node_local(node, local_tag_name)
    if not node or not node._children then
        return nil
    end
    for _, child in ipairs(node._children) do
        if local_name(child._name) == local_tag_name then
            return child
        end
    end
    return nil
end

-- Extract SOAP operation details
local function extract_soap_request(parsed_xml)
    if not parsed_xml then
        return nil, "No parsed XML provided"
    end

    local result = {
        soap_version = nil,
        operation = nil,
        namespace = nil,
        headers = {},
        params = {},
    }

    -- Find Envelope (handle different namespace prefixes)
    local envelope = parsed_xml
    local envelope_name = local_name(envelope._name)
    if envelope_name ~= "Envelope" then
        return nil, "Root element is not a SOAP Envelope, got: " .. (envelope._name or "nil")
    end

    -- Detect SOAP version from namespace
    local env_attrs = envelope._attrs or {}
    for attr_name, attr_value in pairs(env_attrs) do
        if attr_value:find("schemas.xmlsoap.org/soap/envelope") then
            result.soap_version = "1.1"
        elseif attr_value:find("www.w3.org/2003/05/soap%-envelope") then
            result.soap_version = "1.2"
        end
    end

    -- Find Header
    local header_node = find_node_local(envelope, "Header")
    if header_node and header_node._children then
        for _, child in ipairs(header_node._children) do
            result.headers[local_name(child._name)] = get_text(child)
        end
    end

    -- Find Body
    local body_node = find_node_local(envelope, "Body")
    if not body_node then
        return nil, "SOAP Body not found"
    end

    -- The first child of Body is the operation
    if body_node._children and #body_node._children > 0 then
        local operation_node = body_node._children[1]
        result.operation = local_name(operation_node._name)

        -- Extract namespace from operation element
        local op_attrs = operation_node._attrs or {}
        if op_attrs.xmlns then
            result.namespace = op_attrs.xmlns
        end

        -- Extract parameters from operation children
        if operation_node._children then
            for _, param in ipairs(operation_node._children) do
                local param_name = local_name(param._name)
                local param_value = get_text(param)

                -- Check if param has children (complex type)
                if param._children and #param._children > 0 and not param._text then
                    local complex = {}
                    for _, sub in ipairs(param._children) do
                        complex[local_name(sub._name)] = get_text(sub)
                    end
                    result.params[param_name] = complex
                else
                    result.params[param_name] = param_value
                end
            end
        end
    end

    return result
end

-- Build a SOAP fault response
local function build_soap_fault(fault_code, fault_string, detail)
    local detail_xml = ""
    if detail then
        detail_xml = "<detail>" .. detail .. "</detail>"
    end
    return '<?xml version="1.0" encoding="UTF-8"?>' ..
        '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">' ..
        '<soap:Body>' ..
        '<soap:Fault>' ..
        '<faultcode>' .. fault_code .. '</faultcode>' ..
        '<faultstring>' .. fault_string .. '</faultstring>' ..
        detail_xml ..
        '</soap:Fault>' ..
        '</soap:Body>' ..
        '</soap:Envelope>'
end

-- Build a simple SOAP response
local function build_soap_response(operation, namespace, response_data)
    local body_parts = {}
    for key, value in pairs(response_data) do
        if type(value) == "table" then
            local inner = {}
            for k, v in pairs(value) do
                table.insert(inner, "<" .. k .. ">" .. tostring(v) .. "</" .. k .. ">")
            end
            table.insert(body_parts, "<" .. key .. ">" .. table.concat(inner) .. "</" .. key .. ">")
        else
            table.insert(body_parts, "<" .. key .. ">" .. tostring(value) .. "</" .. key .. ">")
        end
    end

    local ns_attr = ""
    if namespace then
        ns_attr = ' xmlns="' .. namespace .. '"'
    end

    return '<?xml version="1.0" encoding="UTF-8"?>' ..
        '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">' ..
        '<soap:Body>' ..
        '<' .. operation .. 'Response' .. ns_attr .. '>' ..
        table.concat(body_parts) ..
        '</' .. operation .. 'Response>' ..
        '</soap:Body>' ..
        '</soap:Envelope>'
end

